  updateLatestDraftMetadata(state.task, draftPath, 'phase5b');
  state.run.review_completed_at = new Date().toISOString();
  await writeArtifactLookup(featureId, runDir);
  await saveState(state);
  console.log('PHASE_5B_COMPLETE');
}

